/// ADD-TRANSACTION
fn p_add_transaction(state: &mut ProgramState) {
    state.tran_record.tran_id = FixedString::high_values();
    p_startbr_transact_file(state);
    p_readprev_transact_file(state);
    p_endbr_transact_file(state);
    state.ws_variables.ws_tran_id_n = state.tran_record.tran_id.trimmed().parse::<u64>().unwrap_or(0);
    state.ws_variables.ws_tran_id_n += 1u64;
    state.tran_record = Default::default();
    state.tran_record.tran_id = (state.ws_variables.ws_tran_id_n).into();
    state.tran_record.tran_type_cd = FixedString::copy_from(&state.cotrn2ai.ttypcdi);
    state.tran_record.tran_cat_cd = state.cotrn2ai.tcatcdi.trimmed().parse::<u32>().unwrap_or(0);
    state.tran_record.tran_source = FixedString::copy_from(&state.cotrn2ai.trnsrci);
    state.tran_record.tran_desc = FixedString::copy_from(&state.cotrn2ai.tdesci);
    state.ws_variables.ws_tran_amt_n = Decimal::from((format!("{}", state.cotrn2ai.trnamti).trim().parse::<f64>().unwrap_or(0.0)) as i64);
    state.tran_record.tran_amt = Decimal::from_i64(state.ws_variables.ws_tran_amt_n.value, state.ws_variables.ws_tran_amt_n.scale);
    state.tran_record.tran_card_num = FixedString::copy_from(&state.cotrn2ai.cardnini);
    state.tran_record.tran_merchant_id = state.cotrn2ai.midi.trimmed().parse::<u32>().unwrap_or(0);
    state.tran_record.tran_merchant_name = FixedString::copy_from(&state.cotrn2ai.mnamei);
    state.tran_record.tran_merchant_city = FixedString::copy_from(&state.cotrn2ai.mcityi);
    state.tran_record.tran_merchant_zip = FixedString::copy_from(&state.cotrn2ai.mzipi);
    state.tran_record.tran_orig_ts = FixedString::copy_from(&state.cotrn2ai.torigdti);
    state.tran_record.tran_proc_ts = FixedString::copy_from(&state.cotrn2ai.tprocdti);
    p_write_transact_file(state);
}

/// COPY-LAST-TRAN-DATA
fn p_copy_last_tran_data(state: &mut ProgramState) {
    p_validate_input_key_fields(state);
    state.tran_record.tran_id = FixedString::high_values();
    p_startbr_transact_file(state);
    p_readprev_transact_file(state);
    p_endbr_transact_file(state);
    if !(state.ws_variables.ws_err_flg == "Y") {
        state.ws_variables.ws_tran_amt_e = u32::from(state.tran_record.tran_amt);
        state.cotrn2ai.ttypcdi = FixedString::copy_from(&state.tran_record.tran_type_cd);
        state.cotrn2ai.tcatcdi = (state.tran_record.tran_cat_cd).into();
        state.cotrn2ai.trnsrci = FixedString::copy_from(&state.tran_record.tran_source);
        state.cotrn2ai.trnamti = (state.ws_variables.ws_tran_amt_e).into();
        state.cotrn2ai.tdesci = FixedString::copy_from(&state.tran_record.tran_desc);
        state.cotrn2ai.torigdti = FixedString::copy_from(&state.tran_record.tran_orig_ts);
        state.cotrn2ai.tprocdti = FixedString::copy_from(&state.tran_record.tran_proc_ts);
        state.cotrn2ai.midi = (state.tran_record.tran_merchant_id).into();
        state.cotrn2ai.mnamei = FixedString::copy_from(&state.tran_record.tran_merchant_name);
        state.cotrn2ai.mcityi = FixedString::copy_from(&state.tran_record.tran_merchant_city);
        state.cotrn2ai.mzipi = FixedString::copy_from(&state.tran_record.tran_merchant_zip);
    }
    p_process_enter_key(state);
}

