fn p_write_transact_file(state: &mut ProgramState) {
    // EXEC CICS WRITE 
    state.cics.execute("WRITE", &[("DATASET", Some("_unknown")), ("WS-TRANSACT-FILE", Some("_unknown")), ("FROM", Some("_unknown")), ("TRAN-RECORD", Some("_unknown")), ("LENGTH", Some("_unknown")), ("LENGTH", Some("OF")), ("TRAN-RECORD", Some("_unknown")), ("RIDFLD", Some("_unknown")), ("TRAN-ID", Some("_unknown")), ("KEYLENGTH", Some("_unknown")), ("LENGTH", Some("OF")), ("TRAN-ID", Some("_unknown")), ("RESP", Some("_unknown")), ("WS-RESP-CD", Some("_unknown")), ("RESP2", Some("_unknown")), ("WS-REAS-CD", Some("_unknown"))]);
    match state.ws_variables.ws_resp_cd {
        _ => {
            p_initialize_all_fields(state);
            state.ws_variables.ws_message = FixedString::spaces();
            state.cotrn2ao.errmsgc = FixedString::copy_from(&state.dfhgreen);
            {
                let mut _str_ptr: usize = 1;
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, "Transaction added successfully. ".as_bytes());
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, " Your Tran ID is ".as_bytes());
                let _bytes_tmp = state.tran_record.tran_id.to_string(); let _src = string_delimited(_bytes_tmp.as_bytes(), b" ");
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, _src);
                string_append(state.ws_variables.ws_message.as_bytes_mut(), &mut _str_ptr, ".".as_bytes());
            }
            p_send_trnadd_screen(state);
        }
        _ | _ => {
            state.ws_variables.ws_err_flg = "Y".into();
            state.ws_variables.ws_message = "Tran ID already exist...".into();
            state.cotrn2ai.actidinl = -1 as i32;
            p_send_trnadd_screen(state);
        }
        _ => {
            println!("{}{}{}{}", "RESP:", state.ws_variables.ws_resp_cd, "REAS:", state.ws_variables.ws_reas_cd);
            state.ws_variables.ws_err_flg = "Y".into();
            state.ws_variables.ws_message = "Unable to Add Transaction...".into();
            state.cotrn2ai.actidinl = -1 as i32;
            p_send_trnadd_screen(state);
        }
    }
}

/// CLEAR-CURRENT-SCREEN
fn p_clear_current_screen(state: &mut ProgramState) {
    p_initialize_all_fields(state);
    p_send_trnadd_screen(state);
}

/// INITIALIZE-ALL-FIELDS
fn p_initialize_all_fields(state: &mut ProgramState) {
    state.cotrn2ai.actidinl = -1 as i32;
    state.cotrn2ai.actidini = FixedString::spaces();
    state.cotrn2ai.cardnini = FixedString::spaces();
    state.cotrn2ai.ttypcdi = FixedString::spaces();
    state.cotrn2ai.tcatcdi = FixedString::spaces();
    state.cotrn2ai.trnsrci = FixedString::spaces();
    state.cotrn2ai.trnamti = FixedString::spaces();
    state.cotrn2ai.tdesci = FixedString::spaces();
    state.cotrn2ai.torigdti = FixedString::spaces();
    state.cotrn2ai.tprocdti = FixedString::spaces();
    state.cotrn2ai.midi = FixedString::spaces();
    state.cotrn2ai.mnamei = FixedString::spaces();
    state.cotrn2ai.mcityi = FixedString::spaces();
    state.cotrn2ai.mzipi = FixedString::spaces();
    state.cotrn2ai.confirmi = FixedString::spaces();
    state.ws_variables.ws_message = FixedString::spaces();
}

